def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            score = (1 - ratio**2) * np.sin(ratio * 4 * np.pi) + np.exp(-ratio * 5)
        elif 0.25 <= ratio < 0.5:
            score = (np.log1p(ratio * 3) ** 2) - np.sqrt(ratio) * 2
        elif 0.5 <= ratio < 0.75:
            score = np.tanh((ratio - 0.5) * 10) + np.cos(ratio * 10) + ratio**3
        elif 0.75 <= ratio < 0.9:
            score = (np.exp(-5 * (1 - ratio))) * (np.sin(ratio * 7 * np.pi) + 1.5)
        else:
            score = np.log(ratio * 10 + 1) * np.tanh(15 * (ratio - 0.9)) + 0.4
        penalty = 0
        for j in range(1, 8):
            mod_val = (item * j) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 4
            elif 0.05 <= frac < 0.15:
                penalty += frac * 2
            elif 0.15 <= frac < 0.35:
                penalty += frac
            elif 0.35 <= frac < 0.6:
                penalty += frac / (j * 0.5)
            else:
                penalty += frac / (j + 2)
            if penalty > 3:
                penalty *= 0.5
                break
        extra_penalty = 0
        for k in range(1, 6):
            if ratio > 0.3 * k:
                extra_penalty += np.exp(-k**2 * ratio) * (k * 1.2)
                for m in range(1, k + 1):
                    extra_penalty += ((ratio * m) % 1) / (k + m)
            else:
                extra_penalty += (np.log1p(k * ratio + m) / (k + 1 + m) for m in range(1, k+1))
                extra_penalty += sum([(np.sin(ratio * m * np.pi)) / (k + m) for m in range(1, k+1)])
        if capacity % 3 == 0:
            multiplier = 1.2
        elif capacity % 2 == 0:
            multiplier = 1.0
        else:
            multiplier = 0.85
        final_score = score + penalty * 1.5 + extra_penalty * multiplier
        if final_score < 0:
            final_score = 0
        priorities[i] = final_score
    return priorities
